import torch
import torch.nn as nn
from torch.utils.cpp_extension import load_inline

# Define optimized CUDA kernel for symmetric matrix multiplication
symmetric_matmul_source = """
#include <torch/extension.h>
#include <cuda_runtime.h>

const int TILE_SIZE = 32;
const int BLOCK_SIZE = 16;

__global__ void symmetric_matmul_kernel(
    const float* __restrict__ A,
    const float* __restrict__ B,
    float* __restrict__ C,
    int N
) {
    // Use shared memory for tiles
    __shared__ float tile_A[BLOCK_SIZE][BLOCK_SIZE];
    __shared__ float tile_B[BLOCK_SIZE][BLOCK_SIZE];

    int bx = blockIdx.x, by = blockIdx.y;
    int tx = threadIdx.x, ty = threadIdx.y;

    // Each thread computes a single element
    int row = by * BLOCK_SIZE + ty;
    int col = bx / BLOCK_SIZE + tx;

    float sum = 0.0f;

    // Loop over tiles
    for (int k = 0; k < N; k += BLOCK_SIZE) {
        // Load A tile
        if (row < N && (k + tx) < N) {
            tile_A[ty][tx] = A[row * N + (k + tx)];
        } else {
            tile_A[ty][tx] = 0.0f;
        }

        // Load B tile
        if ((k + ty) < N && col < N) {
            tile_B[ty][tx] = B[(k + ty) * N + col];
        } else {
            tile_B[ty][tx] = 0.0f;
        }

        __syncthreads();

        // Compute partial sum
        for (int i = 0; i < BLOCK_SIZE; i++) {
            sum += tile_A[ty][i] * tile_B[i][tx];
        }

        __syncthreads();
    }

    // Write result with bounds checking
    if (row < N && col < N) {
        C[row * N + col] = sum;
    }
}

torch::Tensor symmetric_matmul_cuda(torch::Tensor A, torch::Tensor B) {
    int N = A.size(0);
    auto C = torch::zeros({N, N}, A.options());

    // Configure grid and block dimensions
    dim3 block_dim(BLOCK_SIZE, BLOCK_SIZE);
    dim3 grid_dim((N + BLOCK_SIZE - 1) / BLOCK_SIZE, 
                  (N + BLOCK_SIZE - 1) / BLOCK_SIZE);

    // Launch kernel
    symmetric_matmul_kernel<<<grid_dim, block_dim>>>(
        A.data_ptr<float>(),
        B.data_ptr<float>(),
        C.data_ptr<float>(),
        N
    );

    return C;
}
"""

symmetric_matmul_cpp_source = """
torch::Tensor symmetric_matmul_cuda(torch::Tensor A, torch::Tensor B);
"""

# Compile the inline CUDA code
symmetric_matmul = load_inline(
    name="symmetric_matmul",
    cpp_sources=symmetric_matmul_cpp_source,
    cuda_sources=symmetric_matmul_source,
    functions=["symmetric_matmul_cuda"],
    verbose=False,
    extra_cflags=["-O3"],
    extra_ldflags=[],
    extra_cuda_cflags=["--use_fast_math", "-O3"],
)

class ModelNew(nn.Module):
    """
    Optimized model for matrix multiplication using custom CUDA kernel.
    """
    def __init__(self):
        super(ModelNew, self).__init__()
        self.symmetric_matmul = symmetric_matmul

    def forward(self, A, B):
        """
        Performs matrix multiplication using custom CUDA kernel.

        Args:
            A (torch.Tensor): Input matrix A, shape (N, N), symmetric.
            B (torch.Tensor): Input matrix B, shape (N, N), symmetric.

        Returns:
            torch::Tensor: Output matrix C, shape (N, N).
        """
        # Ensure inputs are on GPU, in float32, and contiguous
        A = A.cuda().float().contiguous()
        B = B.cuda().float().contiguous()

        # Use custom kernel
        return self.symmetric_matmul.symmetric_matmul_cuda(A, B)

